const data = $input.first().json;

function makeSlug(nome) {
  const semTam = nome.replace(/\s+(\d+(\/\d+)?(\s+un)?|un)\)\s*$/, ')').replace(/[()]/g, ' ');
  return semTam
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

if (data.status === 'success' && data.data?.items) {
  const grupos = {};
  for (const item of data.data.items) {
    const agrup = item.agrupador || item.codigo;
    if (!grupos[agrup]) {
      const slug = makeSlug(item.nome);
      grupos[agrup] = {
        nome: item.nomeCompleto ? item.nomeCompleto.split(' - ')[0] : item.nome,
        codigo_pai: agrup.split('-')[0],
        tamanhos: [],
        link: 'https://www.chinelarialeilaneneves.com.br/' + slug
      };
    }
    const tamDeriv = (item.derivacoes || []).find(d => d.derivacao === 2);
    if (tamDeriv) {
      grupos[agrup].tamanhos.push(tamDeriv.valor);
    }
  }
  const produtos = Object.values(grupos).map(g => ({
    ...g,
    tamanhos: g.tamanhos.join(', ')
  }));
  return [{ json: { total: produtos.length, produtos } }];
}

return [{ json: { erro: 'Nenhum produto encontrado' } }];
